265	/// A closed batch run over one or more theories.
266	///
267	/// stderr: the maude preamble, then per theory the five progress markers followed
268	/// by any extra engine progress. stdout: the printed payloads (in order), then one
269	/// combined summary block.
270	pub fn frame_batch(maude: &MaudeInfo, theories: &[BatchTheory]) -> Streams {
271	    let mut s = Streams::default();
272	    s.err.push_str(&maude_preamble(maude));
273	    for t in theories {
274	        s.err.push_str(&progress_block(&t.name, &CLOSED_PHASES));
275	        s.err.push_str(&t.extra_progress);
276	    }
277	    for t in theories {
278	        if let Some(p) = &t.payload {
279	            s.out.push_str(p);
280	        }
281	    }
282	    let summaries: Vec<Summary> = theories.iter().map(|t| t.summary.clone()).collect();
283	    s.out.push_str(&render_summary(&summaries));
284	    s
285	}
