295	/// A `--parse-only` run: stderr carries one `Theory loaded` marker per theory (no
296	/// preamble); stdout carries the concatenated payloads (no summary block).
297	pub fn frame_parse_only(theories: &[LoadedTheory]) -> Streams {
298	    let mut s = Streams::default();
299	    for t in theories {
300	        s.err.push_str(&progress_line(&t.name, Phase::Loaded));
301	        s.out.push_str(&t.payload);
302	    }
303	    s
304	}
